# railway.env.map — DECLARATIVE manifest: which variable goes to which service.
# Push with scripts/railway-sync-env.sh (reads the root .env + this manifest).
# Format:  VAR_NAME  service1,service2
#
# Do NOT list here (the script blocks them): DATABASE_URL, REDIS_URL, PORT —
# Railway provides these via fromService/reference (DATABASE_URL ← draw-db).
#
# noddle-draw is anonymous-only with client-side BYOK: every variable below is
# OPTIONAL — when missing the app degrades (AI answers 503, log shipping off),
# it never crashes.

# — Shared AI pool (optional — users bring their own key in the app) —
DATABRICKS_HOST             draw-web
DATABRICKS_TOKEN            draw-web
DATABRICKS_CONFIG_PROFILE   draw-web
DATABRICKS_CLAUDE_ENDPOINT  draw-web

# — Zero-cost free tier: OpenRouter :free pool + guards (all optional) —
OPENROUTER_POOL_KEY         draw-web
POOL_MODEL                  draw-web
POOL_RPM_PER_IP             draw-web
POOL_RPD_PER_IP             draw-web
POOL_DAILY_BUDGET           draw-web
TURNSTILE_SECRET            draw-web
TURNSTILE_SITE_KEY          draw-web

# — CORS for dev tooling (prod is same-origin, usually not needed) —
NODDLE_ALLOWED_ORIGINS      draw-web

# — S3/R2 object storage for log shipping (optional) —
S3_ENDPOINT_URL             draw-web
S3_BUCKET                   draw-web
S3_ACCESS_KEY_ID            draw-web
S3_SECRET_ACCESS_KEY        draw-web
S3_REGION                   draw-web
